"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[378],{728:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new Controller for the given GUI instance.","params":[{"name":"gui","desc":"The GUI instance to manage","lua_type":"ScreenGui | SurfaceGui | BillboardGui"}],"returns":[{"desc":"A new Controller for the given GUI instance","lua_type":"Controller"}],"function_type":"static","source":{"line":92,"path":"src/Flux/Controller.luau"}},{"name":"Unmount","desc":"Destroys the GUI `Instance` and disconnects all bindings. This should be called when you\\nare finished with the GUI to properly clean up resources and prevent memory leaks.\\n\\n```lua\\nlocal controller = Flux:MountScreenGui(gui)\\ncontroller:Unmount() -- Clean up when done\\n```","params":[{"name":"self","desc":"","lua_type":"Self"}],"returns":[],"function_type":"static","source":{"line":111,"path":"src/Flux/Controller.luau"}},{"name":"GetInstance","desc":"Returns the GUI instance managed by this controller.\\n\\n```lua\\nlocal gui = controller:GetInstance()\\nlocal frame = gui:FindFirstChild(\\"Frame\\")\\n```","params":[{"name":"self","desc":"","lua_type":"Self"}],"returns":[{"desc":"The managed GUI instance","lua_type":"ScreenGui | SurfaceGui | BillboardGui"}],"function_type":"static","source":{"line":126,"path":"src/Flux/Controller.luau"}},{"name":"Mount","desc":"Applies a reusable `Component` function to a child instance. The component receives a `Scope`\\nthat allows it to bind to reactive state. All bindings made by the component are automatically\\ncleaned up when the controller is unmounted.\\n\\n\\n```lua\\nlocal function HealthBar(instance: Instance, scope: Flux.Scope, props: {health: Flux.State<number>})\\n\\tscope:Bind(props.health, function(hp: number)\\n\\t\\tlocal bar: Frame = instance :: Frame\\n\\t\\tbar.Size = UDim2.fromScale(hp / 100, 1)\\n\\tend)\\nend\\n\\nlocal healthState = Flux:State(100)\\nlocal healthBarFrame = controller:GetInstance():FindFirstChild(\\"HealthBarFrame\\")\\nif healthBarFrame then\\n\\tcontroller:Mount(HealthBar, healthBarFrame, {health = healthState})\\nend\\n```","params":[{"name":"self","desc":"","lua_type":"Self"},{"name":"component","desc":"The component function to apply","lua_type":"Component"},{"name":"instance","desc":"The GUI instance to pass to the component","lua_type":"Instance"},{"name":"props","desc":"Optional props table to pass to the component","lua_type":"{[string]: any}?"}],"returns":[],"function_type":"static","source":{"line":154,"path":"src/Flux/Controller.luau"}},{"name":"Bind","desc":"Binds to a `State` object so that `callback` fires immediately with the current value,\\nand then again every time the state changes. The binding is automatically cleaned up when\\nthe controller is unmounted.\\n\\n```lua\\nlocal coins: Flux.State<number> = Flux:State(0)\\ncontroller:Bind(coins, function(count: number)\\n\\tlocal label = controller:GetInstance():FindFirstChild(\\"CoinsLabel\\")\\n\\tif label and label:IsA(\\"TextLabel\\") then\\n\\t\\tlabel.Text = tostring(count)\\n\\tend\\nend)\\n```","params":[{"name":"self","desc":"","lua_type":"Self"},{"name":"state","desc":"The reactive state to observe","lua_type":"State<T>"},{"name":"callback","desc":"Function to call with the current and future values","lua_type":"(newValue: T?) -> ()"}],"returns":[],"function_type":"static","source":{"line":179,"path":"src/Flux/Controller.luau"}}],"properties":[],"types":[{"name":"Scope","desc":"A lifecycle scope passed to each component function. Use `Bind` to subscribe to reactive state and `Mount`\\nto compose child components. All bindings and child mounts made through this scope are automatically cleaned\\nup when the parent GUI is unmounted.","fields":[{"name":"Bind","lua_type":"(self, state: State<T>, callback: (newValue: T?) -> ()) -> ()","desc":"Binds to a `State` scoped to this component\'s lifecycle"},{"name":"Mount","lua_type":"(self, component: Component, instance: Instance, props: {[string]: any}?) -> ()","desc":"Mounts a child component scoped to this component\'s lifecycle"}],"source":{"line":14,"path":"src/Flux/Controller.luau"}},{"name":"Component","desc":"A reusable function that applies behavior to a GUI child `Instance`. Components are mounted to a specific\\n`Instance` in the GUI hierarchy and can bind to reactive state using the provided `Scope`. Components\\nshould be used for reusable pieces of UI behavior. For example, you might have a \\"HealthBar\\" component that\\nyou mount to any Frame to turn it into a health bar, or a \\"Draggable\\" component that makes a GUI element\\ndraggable. Components should not manage the lifecycle of their own `Instance` (i.e. by destroying it or\\nreparenting it), they should only be responsible for updating the instance\'s properties in response to state changes,\\npassed down through `props` or observed via `Bind`. Let the parent `Controller` manage the lifecycle of all instances.","lua_type":"(instance: Instance, scope: Scope, props: {[string]: any}?) -> ()","source":{"line":31,"path":"src/Flux/Controller.luau"}},{"name":"State","desc":"A reactive state object. Create these using `Flux:State` and pass them to\\n`Controller:Bind` or `Scope:Bind` inside components to reactively drive UI updates.","source":{"line":40,"path":"src/Flux/Controller.luau"}},{"name":"Self","desc":"","lua_type":"Controller","source":{"line":56,"path":"src/Flux/Controller.luau"}}],"name":"Controller","desc":"Controller for a mounted GUI. Returned by every `Mount` method call. A `Controller` manages the lifecycle of\\nthe GUI `Instance` and all reactive connections. Call `Unmount` to clean up, `Bind` to react to state changes,\\nand `Mount` to apply reusable components that are automatically cleaned up when the controller is unmounted.\\nAccess the GUI hierarchy via `GetInstance()`.","source":{"line":66,"path":"src/Flux/Controller.luau"}}')}}]);